-- calc_capabilities_name
-- Field: Capabilities.Name
-- Type: calculated | DataType: string | Returns: TEXT


CREATE OR REPLACE FUNCTION calc_capabilities_name(p_capabilities_id TEXT)
RETURNS TEXT AS $$
  SELECT ((SELECT NULLIF(capabilities_id, '') FROM capabilities WHERE capabilities_id = p_capabilities_id))::text;
$$ LANGUAGE sql STABLE;

-- calc_intelligences_name
-- Field: Intelligences.Name
-- Type: calculated | DataType: string | Returns: TEXT


CREATE OR REPLACE FUNCTION calc_intelligences_name(p_intelligences_id TEXT)
RETURNS TEXT AS $$
  SELECT ((SELECT NULLIF(intelligences_id, '') FROM intelligences WHERE intelligences_id = p_intelligences_id))::text;
$$ LANGUAGE sql STABLE;

-- calc_intelligences_assessment_count
-- Field: Intelligences.AssessmentCount
-- Type: aggregation | DataType: integer | Returns: INTEGER


CREATE OR REPLACE FUNCTION calc_intelligences_assessment_count(p_intelligences_id TEXT)
RETURNS INTEGER AS $$
  SELECT ((SELECT COUNT(*) FROM assessments WHERE intelligence = (SELECT NULLIF(intelligences_id, '') FROM intelligences WHERE intelligences_id = p_intelligences_id)))::integer;
$$ LANGUAGE sql STABLE;

-- calc_intelligences_total_weighted_score
-- Field: Intelligences.TotalWeightedScore
-- Type: aggregation | DataType: number | Returns: NUMERIC


CREATE OR REPLACE FUNCTION calc_intelligences_total_weighted_score(p_intelligences_id TEXT)
RETURNS NUMERIC AS $$
  SELECT ((SELECT COALESCE(SUM((calc_assessments_weighted_score(assessments_id))::numeric), 0) FROM assessments WHERE intelligence = p_intelligences_id))::numeric;
$$ LANGUAGE sql STABLE;

-- calc_intelligences_taxonomy_class
-- Field: Intelligences.TaxonomyClass
-- Type: calculated | DataType: string | Returns: TEXT


CREATE OR REPLACE FUNCTION calc_intelligences_taxonomy_class(p_intelligences_id TEXT)
RETURNS TEXT AS $$
  SELECT (CASE WHEN (calc_intelligences_total_weighted_score(p_intelligences_id))::NUMERIC >= 350 THEN ('Generalist')::text ELSE (CASE WHEN (calc_intelligences_total_weighted_score(p_intelligences_id))::NUMERIC >= 220 THEN ('Broad')::text ELSE ('Narrow')::text END)::text END)::text;
$$ LANGUAGE sql STABLE;

